// Normalize slot from parent and preserve as _slot for downstream access
const s = $input.first().json;
return [{
  json: {
    provider_id:      Number(s.provider_id),
    service_id:       Number(s.service_id),
    start_time:       String(s.start_time),
    duration_minutes: Number(s.duration_minutes || 60),
    _slot: {
      provider_id:     Number(s.provider_id),
      service_id:      Number(s.service_id),
      start_time:      String(s.start_time),
      end_time:        String(s.end_time || ''),
      chat_id:         Number(s.chat_id),
      idempotency_key: String(s.idempotency_key),
      duration_minutes:Number(s.duration_minutes || 60),
      source:          String(s.source || 'SEED_01')
    }
  }
}];

const err  = $input.first().json;
const slot = $('Prepare WF3 Input').first().json._slot;
return [{
  json: {
    success:         false,
    slot:            slot?.start_time || 'unknown',
    error_code:      'WF3_ERROR',
    error_message:   err.message || err.error?.message || 'WF3 availability check failed',
    idempotency_key: slot?.idempotency_key || null,
    source:          'SEED_01',
    _meta: { source: 'SEED_01_Process_Slot', timestamp: new Date().toISOString() }
  }
}];

const slot = $('Prepare WF3 Input').first().json._slot;
return [{
  json: {
    provider_id: slot.provider_id,
    service_id:  slot.service_id,
    start_time:  slot.start_time,
    chat_id:     String(slot.chat_id),
    user_name:   'SEED Booking',
    _slot:       slot
  }
}];

const availResponse = $input.first().json;
const slot = $('Prepare WF3 Input').first().json._slot;
return [{
  json: {
    success:         false,
    slot:            slot.start_time,
    error_code:      'SLOT_UNAVAILABLE',
    error_message:   availResponse.data?.gcal_error || availResponse.error_message || 'Slot not available',
    idempotency_key: slot.idempotency_key,
    source:          slot.source,
    _meta: { source: 'SEED_01_Process_Slot', timestamp: new Date().toISOString() }
  }
}];

const err  = $input.first().json;
const slot = $('Prepare WF2 Input').first().json._slot;
return [{
  json: {
    success:         false,
    slot:            slot?.start_time || 'unknown',
    error_code:      'WF2_ERROR',
    error_message:   err.message || err.error?.message || 'WF2 booking orchestrator failed',
    idempotency_key: slot?.idempotency_key || null,
    source:          'SEED_01',
    _meta: { source: 'SEED_01_Process_Slot', timestamp: new Date().toISOString() }
  }
}];

const booking = $input.first().json;
const slot    = $('Prepare WF2 Input').first().json._slot;
return [{
  json: {
    success:         true,
    slot:            slot.start_time,
    booking_id:      booking.data?.booking_id || null,
    idempotency_key: slot.idempotency_key,
    chat_id:         slot.chat_id,
    status:          booking.data?.status || 'CONFIRMED',
    source:          slot.source,
    _meta: { source: 'SEED_01_Process_Slot', timestamp: new Date().toISOString() }
  }
}];
